#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>

#include "./../main.h"
#include "./../util/avi/avilib.h"
#include "./../util/avi/avimod.h"

// Removed #include "./kernel_gpu_opencl_wrapper.h" to fix compilation error

extern int platform_id_inuse;
extern int device_id_inuse;

void 
kernel_gpu_opencl_wrapper(	params_common common,
							int* endoRow,
							int* endoCol,
							int* tEndoRowLoc,
							int* tEndoColLoc,
							int* epiRow,
							int* epiCol,
							int* tEpiRowLoc,
							int* tEpiColLoc,
							avi_t* frames)
{
#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

	int i;
	cudaError_t error;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

	// Set device (select best device)
	setdevice();

	// Allocate device memory
	params_common* d_common;
	error = cudaMalloc((void**)&d_common, sizeof(params_common));
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_common failed\n");
		exit(1);
	}

	fp* d_frame;
	error = cudaMalloc((void**)&d_frame, common.frame_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_frame failed\n");
		exit(1);
	}

	int* d_endoRow;
	error = cudaMalloc((void**)&d_endoRow, common.endo_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_endoRow failed\n");
		exit(1);
	}
	int* d_endoCol;
	error = cudaMalloc((void**)&d_endoCol, common.endo_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_endoCol failed\n");
		exit(1);
	}
	int* d_tEndoRowLoc;
	error = cudaMalloc((void**)&d_tEndoRowLoc, common.endo_mem * common.no_frames);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_tEndoRowLoc failed\n");
		exit(1);
	}
	int* d_tEndoColLoc;
	error = cudaMalloc((void**)&d_tEndoColLoc, common.endo_mem * common.no_frames);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_tEndoColLoc failed\n");
		exit(1);
	}

	int* d_epiRow;
	error = cudaMalloc((void**)&d_epiRow, common.epi_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_epiRow failed\n");
		exit(1);
	}
	int* d_epiCol;
	error = cudaMalloc((void**)&d_epiCol, common.epi_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_epiCol failed\n");
		exit(1);
	}
	int* d_tEpiRowLoc;
	error = cudaMalloc((void**)&d_tEpiRowLoc, common.epi_mem * common.no_frames);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_tEpiRowLoc failed\n");
		exit(1);
	}
	int* d_tEpiColLoc;
	error = cudaMalloc((void**)&d_tEpiColLoc, common.epi_mem * common.no_frames);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_tEpiColLoc failed\n");
		exit(1);
	}

	fp* d_endoT;
	error = cudaMalloc((void**)&d_endoT, common.in_mem * common.endoPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_endoT failed\n");
		exit(1);
	}

	fp* d_epiT;
	error = cudaMalloc((void**)&d_epiT, common.in_mem * common.epiPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_epiT failed\n");
		exit(1);
	}

	fp* d_in2_all;
	error = cudaMalloc((void**)&d_in2_all, common.in2_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in2_all failed\n");
		exit(1);
	}

	fp* d_conv_all;
	error = cudaMalloc((void**)&d_conv_all, common.conv_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_conv_all failed\n");
		exit(1);
	}

	fp* d_in2_pad_cumv_all;
	error = cudaMalloc((void**)&d_in2_pad_cumv_all, common.in2_pad_cumv_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in2_pad_cumv_all failed\n");
		exit(1);
	}

	fp* d_in2_pad_cumv_sel_all;
	error = cudaMalloc((void**)&d_in2_pad_cumv_sel_all, common.in2_pad_cumv_sel_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in2_pad_cumv_sel_all failed\n");
		exit(1);
	}

	fp* d_in2_sub_cumh_all;
	error = cudaMalloc((void**)&d_in2_sub_cumh_all, common.in2_sub_cumh_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in2_sub_cumh_all failed\n");
		exit(1);
	}

	fp* d_in2_sub_cumh_sel_all;
	error = cudaMalloc((void**)&d_in2_sub_cumh_sel_all, common.in2_sub_cumh_sel_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in2_sub_cumh_sel_all failed\n");
		exit(1);
	}

	fp* d_in2_sub2_all;
	error = cudaMalloc((void**)&d_in2_sub2_all, common.in2_sub2_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in2_sub2_all failed\n");
		exit(1);
	}

	fp* d_in2_sqr_all;
	error = cudaMalloc((void**)&d_in2_sqr_all, common.in2_sqr_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in2_sqr_all failed\n");
		exit(1);
	}

	fp* d_in2_sqr_sub2_all;
	error = cudaMalloc((void**)&d_in2_sqr_sub2_all, common.in2_sqr_sub2_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in2_sqr_sub2_all failed\n");
		exit(1);
	}

	fp* d_in_sqr_all;
	error = cudaMalloc((void**)&d_in_sqr_all, common.in_sqr_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in_sqr_all failed\n");
		exit(1);
	}

	fp* d_tMask_all;
	error = cudaMalloc((void**)&d_tMask_all, common.tMask_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_tMask_all failed\n");
		exit(1);
	}

	fp* d_mask_conv_all;
	error = cudaMalloc((void**)&d_mask_conv_all, common.mask_conv_mem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_mask_conv_all failed\n");
		exit(1);
	}

	fp* d_in_mod_temp_all;
	error = cudaMalloc((void**)&d_in_mod_temp_all, sizeof(fp) * common.in_elem * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_in_mod_temp_all failed\n");
		exit(1);
	}

	fp* in_partial_sum_all;
	error = cudaMalloc((void**)&in_partial_sum_all, sizeof(fp) * common.in_cols * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc in_partial_sum_all failed\n");
		exit(1);
	}

	fp* in_sqr_partial_sum_all;
	error = cudaMalloc((void**)&in_sqr_partial_sum_all, sizeof(fp) * common.in_sqr_rows * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc in_sqr_partial_sum_all failed\n");
		exit(1);
	}

	fp* par_max_val_all;
	error = cudaMalloc((void**)&par_max_val_all, sizeof(fp) * common.mask_conv_rows * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc par_max_val_all failed\n");
		exit(1);
	}

	int* par_max_coo_all;
	error = cudaMalloc((void**)&par_max_coo_all, sizeof(int) * common.mask_conv_rows * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc par_max_coo_all failed\n");
		exit(1);
	}

	fp* in_final_sum_all;
	error = cudaMalloc((void**)&in_final_sum_all, sizeof(fp) * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc in_final_sum_all failed\n");
		exit(1);
	}

	fp* in_sqr_final_sum_all;
	error = cudaMalloc((void**)&in_sqr_final_sum_all, sizeof(fp) * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc in_sqr_final_sum_all failed\n");
		exit(1);
	}

	fp* denomT_all;
	error = cudaMalloc((void**)&denomT_all, sizeof(fp) * common.allPoints);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc denomT_all failed\n");
		exit(1);
	}

	fp* d_checksum;
	error = cudaMalloc((void**)&d_checksum, sizeof(fp) * CHECK);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_checksum failed\n");
		exit(1);
	}

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	// Copy host data to device
	error = cudaMemcpy(d_endoRow, endoRow, common.endo_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_endoRow failed\n");
		exit(1);
	}
	error = cudaMemcpy(d_endoCol, endoCol, common.endo_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_endoCol failed\n");
		exit(1);
	}
	error = cudaMemcpy(d_epiRow, epiRow, common.epi_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_epiRow failed\n");
		exit(1);
	}
	error = cudaMemcpy(d_epiCol, epiCol, common.epi_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_epiCol failed\n");
		exit(1);
	}

	// Copy common struct to device
	error = cudaMemcpy(d_common, &common, sizeof(params_common), cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_common failed\n");
		exit(1);
	}

	size_t local_work_size = NUMBER_THREADS;
	size_t global_work_size = common.allPoints * local_work_size;

	printf("# of workgroups = %zu, # of threads/workgroup = %zu (ensure that device can handle)\n", global_work_size / local_work_size, local_work_size);

	printf("frame progress: ");
	fflush(NULL);

	for(int frame_no=0; frame_no<common.frames_processed; frame_no++){

		fp* frame = get_frame(frames, frame_no, 0, 0, 1);
		if (!frame) {
			fprintf(stderr, "get_frame failed for frame %d\n", frame_no);
			exit(1);
		}

		error = cudaMemcpy(d_frame, frame, common.frame_mem, cudaMemcpyHostToDevice);
		if (error != cudaSuccess) {
			fprintf(stderr, "cudaMemcpy d_frame failed\n");
			exit(1);
		}

		// Launch kernel
#ifdef TIMING
		gettimeofday(&tv_kernel_start, NULL);
#endif
		kernel_gpu_opencl<<<common.allPoints, NUMBER_THREADS>>>(common,
			d_frame,
			frame_no,
			d_endoRow,
			d_endoCol,
			d_tEndoRowLoc,
			d_tEndoColLoc,
			d_epiRow,
			d_epiCol,
			d_tEpiRowLoc,
			d_tEpiColLoc,
			d_endoT,
			d_epiT,
			d_in2_all,
			d_conv_all,
			d_in2_pad_cumv_all,
			d_in2_pad_cumv_sel_all,
			d_in2_sub_cumh_all,
			d_in2_sub_cumh_sel_all,
			d_in2_sub2_all,
			d_in2_sqr_all,
			d_in2_sqr_sub2_all,
			d_in_sqr_all,
			d_tMask_all,
			d_mask_conv_all,
			d_in_mod_temp_all,
			in_partial_sum_all,
			in_sqr_partial_sum_all,
			par_max_val_all,
			par_max_coo_all,
			in_final_sum_all,
			in_sqr_final_sum_all,
			denomT_all,
			d_checksum);
		error = cudaGetLastError();
		if (error != cudaSuccess) {
			fprintf(stderr, "Kernel launch failed: %s\n", cudaGetErrorString(error));
			exit(1);
		}
		error = cudaDeviceSynchronize();
		if (error != cudaSuccess) {
			fprintf(stderr, "cudaDeviceSynchronize failed: %s\n", cudaGetErrorString(error));
			exit(1);
		}
#ifdef TIMING
		gettimeofday(&tv_kernel_end, NULL);
		tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
		kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

		free(frame);

		printf("%d ", frame_no);
		fflush(NULL);

#ifdef TEST_CHECKSUM
		fp* checksum = (fp*)malloc(sizeof(fp) * CHECK);
		if (!checksum) {
			fprintf(stderr, "malloc checksum failed\n");
			exit(1);
		}
		error = cudaMemcpy(checksum, d_checksum, sizeof(fp)*CHECK, cudaMemcpyDeviceToHost);
		if (error != cudaSuccess) {
			fprintf(stderr, "cudaMemcpy checksum failed\n");
			exit(1);
		}
		printf("CHECKSUM:\n");
		for(i=0; i<CHECK; i++){
				printf("%f ", checksum[i]);
		}
		printf("\n\n");
		free(checksum);
#endif

	}

	printf("\n");
	fflush(NULL);

	// Copy results back to host
	error = cudaMemcpy(tEndoRowLoc, d_tEndoRowLoc, common.endo_mem * common.no_frames, cudaMemcpyDeviceToHost);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy tEndoRowLoc failed\n");
		exit(1);
	}
	error = cudaMemcpy(tEndoColLoc, d_tEndoColLoc, common.endo_mem * common.no_frames, cudaMemcpyDeviceToHost);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy tEndoColLoc failed\n");
		exit(1);
	}
	error = cudaMemcpy(tEpiRowLoc, d_tEpiRowLoc, common.epi_mem * common.no_frames, cudaMemcpyDeviceToHost);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy tEpiRowLoc failed\n");
		exit(1);
	}
	error = cudaMemcpy(tEpiColLoc, d_tEpiColLoc, common.epi_mem * common.no_frames, cudaMemcpyDeviceToHost);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy tEpiColLoc failed\n");
		exit(1);
	}

#ifdef TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	// Free device memory
	cudaFree(d_common);
	cudaFree(d_frame);
	cudaFree(d_endoRow);
	cudaFree(d_endoCol);
	cudaFree(d_tEndoRowLoc);
	cudaFree(d_tEndoColLoc);
	cudaFree(d_epiRow);
	cudaFree(d_epiCol);
	cudaFree(d_tEpiRowLoc);
	cudaFree(d_tEpiColLoc);
	cudaFree(d_endoT);
	cudaFree(d_epiT);
	cudaFree(d_in2_all);
	cudaFree(d_conv_all);
	cudaFree(d_in2_pad_cumv_all);
	cudaFree(d_in2_pad_cumv_sel_all);
	cudaFree(d_in2_sub_cumh_all);
	cudaFree(d_in2_sub_cumh_sel_all);
	cudaFree(d_in2_sub2_all);
	cudaFree(d_in2_sqr_all);
	cudaFree(d_in2_sqr_sub2_all);
	cudaFree(d_in_sqr_all);
	cudaFree(d_tMask_all);
	cudaFree(d_mask_conv_all);
	cudaFree(d_in_mod_temp_all);
	cudaFree(in_partial_sum_all);
	cudaFree(in_sqr_partial_sum_all);
	cudaFree(par_max_val_all);
	cudaFree(par_max_coo_all);
	cudaFree(in_final_sum_all);
	cudaFree(in_sqr_final_sum_all);
	cudaFree(denomT_all);
	cudaFree(d_checksum);

#ifdef TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
	tvsub(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

	printf("Time spent in different stages of the application:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}
